import subprocess
import sys
import os
import shutil

REQUIREMENTS_FILE = "requirements.txt"
TEST_COMMAND = [sys.executable, "-m", "pytest"] # Assuming pytest is used
PACKAGE_DIR = "dist"
APP_NAME = "my_application" # Replace with your actual application name
VERSION = "1.0.0" # Replace with your actual versioning logic (e.g., from a file or git tag)
PACKAGE_FORMAT = "zip" # Options: zip, tar.gz

def install_dependencies():
    print(f"Installing dependencies from {REQUIREMENTS_FILE}...")
    try:
        subprocess.check_call([sys.executable, "-m", "pip", "install", "-r", REQUIREMENTS_FILE])
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error installing dependencies: {e}")
        sys.exit(1)

def run_tests():
    print("Running application tests...")
    try:
        # Set environment variables for tests if needed, e.g., TEST_MODE=true
        # env = os.environ.copy()
        # env['TEST_MODE'] = 'true'
        subprocess.check_call(TEST_COMMAND) #, env=env)
        print("Tests passed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Tests failed: {e}")
        sys.exit(1)

def package_application():
    print("Packaging application for deployment...")

    if os.path.exists(PACKAGE_DIR):
        shutil.rmtree(PACKAGE_DIR)
    os.makedirs(PACKAGE_DIR)

    package_name = f"{APP_NAME}-{VERSION}"
    archive_path_base = os.path.join(PACKAGE_DIR, package_name)

    # List of files/directories to include in the package
    # Customize this list based on your project structure
    items_to_package = [
        "requirements.txt",
        "app/", # Your main application code directory
        "config/", # Configuration files
        "scripts/", # Deployment scripts
        "static/", # Static assets
        "templates/", # HTML templates
        "wsgi.py", # WSGI entry point if applicable
        "manage.py", # Django/Flask management script
        # Add any other necessary files or directories
    ]

    temp_package_dir = os.path.join(PACKAGE_DIR, package_name)
    os.makedirs(temp_package_dir, exist_ok=True)

    for item in items_to_package:
        if os.path.exists(item):
            destination = os.path.join(temp_package_dir, os.path.basename(item))
            if os.path.isfile(item):
                shutil.copy2(item, destination)
            elif os.path.isdir(item):
                shutil.copytree(item, destination)
        else:
            print(f"Warning: Item '{item}' not found for packaging.")

    try:
        archive_name = shutil.make_archive(archive_path_base, PACKAGE_FORMAT, root_dir=PACKAGE_DIR, base_dir=package_name)
        print(f"Application packaged successfully: {archive_name}")
        shutil.rmtree(temp_package_dir) # Clean up temporary directory
    except Exception as e:
        print(f"Error packaging application: {e}")
        sys.exit(1)

def main():
    print("Starting production deployment workflow...")
    
    install_dependencies()
    run_tests()
    package_application()
    
    print("Deployment workflow completed successfully.")

if __name__ == "__main__":
    main()